function solve(code, businessLine, isActive) {
    const valid = [];
    const codeRegex = /^[a-zA-Z0-9_]+$/;
    const allowedBusiness = new Set(["electronics", "grocery", "pharmacy", "restaurant"]);
    const businessOrder = {
        electronics: 0,
        grocery: 1,
        pharmacy: 2,
        restaurant: 3
    };

    for (let i = 0; i < code.length; i++) {
        const c = code[i];
        const bl = businessLine[i];
        const active = isActive[i];

        if (c && codeRegex.test(c) && allowedBusiness.has(bl) && active) {
            valid.push({ code: c, businessLine: bl });
        }
    }

    valid.sort((a, b) => {
        if (a.businessLine !== b.businessLine) {
            return businessOrder[a.businessLine] - businessOrder[b.businessLine];
        } else {
            return a.code.localeCompare(b.code);
        }
    });

    return valid.map(c => c.code);
}
